    (function() {
    const PHOTO_B64 = 'data:image/png;base64,';

    const canvas = document.getElementById('heroCanvas');
    const ctx = canvas.getContext('2d');

    let W, H;
    let particles = [];
    let imageLoaded = false;
    
    let animationMode = 'waiting'; // waiting -> auto -> scroll
    let autoProgress = 0;
    let scrollProgress = 1; 

    const GRID = 2;
    const P_SIZE = 1;
    const PADDING_RIGHT = 0; 
    const PADDING_BOTTOM = 0;

    function resize() {
      W = canvas.offsetWidth;
      H = canvas.offsetHeight;
      canvas.width = W;
      canvas.height = H;
      updateTargets();
    }

    function updateTargets() {
      if (!particles.length) return;
      particles.forEach(p => {
        p.tx = W - p.relX;
        p.ty = H - p.relY;
      });
    }

    function samplePhoto(img) {
      const ph = Math.min(H * 0.78, 580);
      const aspect = img.naturalWidth / img.naturalHeight;
      const pw = ph * aspect;
      const oc = document.createElement('canvas');
      oc.width = Math.round(pw); oc.height = Math.round(ph);
      const c2 = oc.getContext('2d');
      c2.drawImage(img, 0, 0, oc.width, oc.height);
      const id = c2.getImageData(0, 0, oc.width, oc.height);
      const d = id.data;

      const pts = [];
      for (let r = 0; r < oc.height; r += GRID) {
        for (let c = 0; c < oc.width; c += GRID) {
          const i = (r * oc.width + c) * 4;
          if (d[i + 3] < 60) continue;
          const ox = -Math.random() * 300 - 100; 
          const oy = Math.random() * H;
          pts.push({
            relX: (pw - c) + PADDING_RIGHT,
            relY: (ph - r) + PADDING_BOTTOM,
            ox, oy, tx: 0, ty: 0,
            gray: Math.round(0.299*d[i] + 0.587*d[i+1] + 0.114*d[i+2]),
            alpha: d[i + 3] / 255,
            size: P_SIZE * (0.7 + (1 - d[i]/255) * 0.5),
            delay: Math.random() * 0.3
          });
        }
      }
      return pts;
    }

    function updateScroll() {
      if (!imageLoaded) return;
      
      const rect = canvas.getBoundingClientRect();
      const windowHeight = window.innerHeight;

      // Если блок полностью ушел вверх или вниз - сбрасываем в ожидание
      if (rect.bottom < 0 || rect.top > windowHeight) {
        animationMode = 'waiting';
        autoProgress = 0;
        return;
      }

      // Если мы уже в режиме скролла, считаем прогресс
      if (animationMode === 'scroll') {
        // 1 - блок полностью виден (снизу окна), 0 - блок уполз вверх
        let p = rect.bottom / (windowHeight * 0.8); 
        scrollProgress = Math.max(0, Math.min(1, p));
      }
    }

    function draw() {
      ctx.clearRect(0, 0, W, H);
      if (!imageLoaded || animationMode === 'waiting') {
        requestAnimationFrame(draw);
        return;
      }

      let finalP = 0;

      if (animationMode === 'auto') {
        autoProgress += 0.01; // Скорость сборки
        finalP = autoProgress;
        if (autoProgress >= 1) {
          animationMode = 'scroll';
        }
      } else if (animationMode === 'scroll') {
        finalP = scrollProgress;
      }

      for (let i = 0; i < particles.length; i++) {
        const pt = particles[i];
        const p = Math.max(0, Math.min(1, (finalP - pt.delay) / (1 - pt.delay)));
        const easeP = 1 - Math.pow(1 - p, 3);

        const curX = pt.ox + (pt.tx - pt.ox) * easeP;
        const curY = pt.oy + (pt.ty - pt.oy) * easeP;

        ctx.beginPath();
        ctx.arc(curX, curY, pt.size, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(${pt.gray},${pt.gray},${pt.gray},${(pt.alpha * easeP).toFixed(2)})`;
        ctx.fill();
      }

      requestAnimationFrame(draw);
    }

    function init() {
      resize();
      window.addEventListener('resize', resize);
      window.addEventListener('scroll', updateScroll);

      const img = new Image();
      img.onload = function() {
        particles = samplePhoto(img);
        updateTargets();
        imageLoaded = true;

        const observer = new IntersectionObserver((entries) => {
          entries.forEach(entry => {
            if (entry.isIntersecting) {
              if (animationMode === 'waiting') {
                animationMode = 'auto';
              }
            }
          });
        }, { threshold: 0.1 });

        observer.observe(canvas);
        requestAnimationFrame(draw);
      };
      img.src = PHOTO_B64;
    }

    if (document.readyState === 'complete') { init(); }
    else { window.addEventListener('load', init); }
  })();
  
